    fun start(onProgress: (Int, Int, String) -> Unit, onFinished: () -> Unit) {
        startWithRegion("CUSTOM", onProgress, onFinished)
    }

    fun startWithRegion(region: String, onProgress: (Int, Int, String) -> Unit, onFinished: () -> Unit) {
        if (isRunning) return
        isRunning = true
        
        val listToUse = when {
            !customAttackList.isNullOrEmpty() -> customAttackList!!
            region == "NA" -> TvBGoneCodes.getNaCodes()
            region == "EU" -> TvBGoneCodes.getEuCodes()
            else -> heavyHitters
        }

        Thread {
            for (i in listToUse.indices) {
                if (!isRunning) break
                
                val cmd = listToUse[i]
                handler.post { onProgress(i + 1, listToUse.size, cmd.name) }
                
                try {
                    irManager?.transmit(cmd.frequency, cmd.pattern)
                } catch (e: Exception) {}
                
                Thread.sleep(205)
            }
            isRunning = false
            handler.post { onFinished() }
        }.start()
    }

    fun stop() {
        isRunning = false
    }
